import classNames from 'classnames';

const App = () => {
 const highlight = classNames('text-yellow-200 bg-amber-700 p-4')
 return (
  &lt;>
   &lt;div className="hase">
    &lt;p>Merkur&lt;/p>
    &lt;p>Venus&lt;/p>
    &lt;p className={highlight}>Erde&lt;/p>
    &lt;p>Mars&lt;/p>
   &lt;/div>
  &lt;/>
 )
}

export default App

import classNames from 'classnames';
import {useState} from "react";

const App = () => {
 const [isDark, setIsDark] = useState(true)
 const themed = classNames(
  'p-4 rounded border', // immer aktiv
  {
   'bg-slate-200 text-sky-800': !isDark,
   'bg-sky-800 text-slate-200': isDark,
  }
 )

 return (
  &lt;>
   &lt;div className={themed}>
    &lt;p>Merkur&lt;/p>
    &lt;p>Venus&lt;/p>
    &lt;p>Erde&lt;/p>
    &lt;p>Mars&lt;/p>
   &lt;/div>
   &lt;button onClick={() => setIsDark(!isDark)}>
    Toggle
   &lt;/button>
  &lt;/>
 )
}

export default App

import classNames from 'classnames';
import {useState} from "react";

const App = () => {
 const [isDark, setIsDark] = useState(true)
 const [isBig, setIsBig] = useState(false)

 const themed = classNames(
  'p-4 rounded border', // immer aktiv
  [
   isDark
    ? 'bg-slate-200 text-sky-800'
    : 'bg-sky-800 text-slate-200',
   isBig
    ? 'text-xl font-bold'
    : 'text-base font-normal'
  ]
 )

 return (
  &lt;>
   &lt;div className={themed}>
    &lt;p>Merkur&lt;/p>
    &lt;p>Venus&lt;/p>
    &lt;p>Erde&lt;/p>
    &lt;p>Mars&lt;/p>
   &lt;/div>
   &lt;button onClick={() => setIsDark(!isDark)}>
    Toggle Dark
   &lt;/button>
   &lt;button onClick={() => setIsBig(!isBig)}>
    Toggle Big
   &lt;/button>
  &lt;/>
 )
}

export default App
